type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload represents the JSON response
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch and parse a URL
func FetchURLPreview(c echo.Context) error {
	var req RequestPayload
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, ResponsePayload{Error: "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, ResponsePayload{Error: "URL field is required"})
	}

	// Create a context with timeout to ensure the request doesn't hang indefinitely
	ctx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create an HTTP client with a 3-second timeout as requested
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create the request
	httpReq, err := http.NewRequestWithContext(ctx, http.MethodGet, req.URL, nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, ResponsePayload{Error: "Failed to create request: " + err.Error()})
	}

	// Set a User-Agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute the request
	resp, err := client.Do(httpReq)
	if err != nil {
		return c.JSON(http.StatusBadGateway, ResponsePayload{Error: "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, ResponsePayload{Error: fmt.Sprintf("Server returned status %d", resp.StatusCode)})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, ResponsePayload{Error: "Failed to parse HTML"})
	}

	var title, description string

	// Traverse the HTML node tree to find title and meta description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc && content != "" {
					description = content
				}
			}
		}

		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	// Return the result
	return c.JSON(http.StatusOK, ResponsePayload{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	})
}

func main() {
