package main

import (
	"fmt"
	"io"
	"log"
	"net"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Security: Validate Host to prevent SSRF
	host := parsedURL.Hostname()
	if host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid hostname"})
	}

	// Resolve host to IPs to prevent DNS rebinding
	ips, err := net.LookupHost(host)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Unable to resolve host"})
	}

	for _, ip := range ips {
		parsedIP := net.ParseIP(ip)
		if parsedIP != nil {
			// Block Loopback, Private, and Link-Local IPs
			if parsedIP.IsLoopback() || parsedIP.IsPrivate() || parsedIP.IsLinkLocalUnicast() || parsedIP.IsLinkLocalMulticast() {
				return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Access to private IP addresses is not allowed"})
			}
		}
	}

	// Fetch the URL
	client := &http.Client{Timeout: 10 * time.Second}
	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	content := string(htmlContent)

	// Extract Title using Regex
	titleRegex := regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	titleMatch := titleRegex.FindStringSubmatch(content)
	var title string
	if len(titleMatch) > 1 {
		title = strings.TrimSpace(titleMatch[1])
	}

	// Extract Description using Regex
	var description string

	// Try matching name="description" content="..."
	descRegex := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["'](.*?)["']`)
	descMatch := descRegex.FindStringSubmatch(content)
	if len(descMatch) > 1 {
		description = strings.TrimSpace(descMatch[1])
	} else {
		// Try matching content="..." name="description"
		descRegex2 := regexp.MustCompile(`(?i)<meta\s+content=["'](.*?)["']\s+name=["']description["']`)
		descMatch2 := descRegex2.FindStringSubmatch(content)
		if len(descMatch2) > 1 {
			description = strings.TrimSpace(descMatch2[1])
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	if err := e.Start(":8080"); err != nil {
		log.Fatal(err)
	}
}

