					if strings.EqualFold(attr.Key, "name") && strings.EqualFold(attr.Val, "description") {
						// Find the content attribute
						for _, a := range token.Attr {
							if strings.EqualFold(a.Key, "content") {
								description = a.Val
								break
							}
						}
					}
					// Also check Open Graph description
					if strings.EqualFold(attr.Key, "property") && strings.EqualFold(attr.Val, "og:description") {
						for _, a := range token.Attr {
							if strings.EqualFold(a.Key, "content") {
								description = a.Val
								break
							}
						}
					}
				}
			}

		case html.TextToken:
			if inTitle {
				title += token.Data
			}

		case html.EndTagToken:
			if token.Data == "title" {
				inTitle = false
			}
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

