package main

import (
	"io"
	"log"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// RequestPayload defines the expected JSON input
type RequestPayload struct {
	URL string `json:"url" validate:"required,url"`
}

// ResponsePayload defines the JSON output
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
	// 1. Bind and validate request
	var req RequestPayload
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON format"})
	}

	// 2. Create HTTP Client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// 3. Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// 4. Check status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "URL returned non-200 status"})
	}

	// 5. Parse HTML
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// 6. Extract metadata
	title, description := extractMeta(doc)

	// 7. Return JSON response
	return ctx.JSON(http.StatusOK, ResponsePayload{
		Title:       title,
		Description: description,
	})
}

// extractMeta traverses the HTML node tree to find the title and meta description
func extractMeta(n *html.Node) (string, string) {
	var title, description string

	if n.Type == html.ElementNode {
		// Extract Title
		if n.Data == "title" && n.FirstChild != nil {
			title = n.FirstChild.Data
		}

		// Extract Meta Description
		if n.Data == "meta" {
			var isDesc bool
			var content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && attr.Val == "description" {
					isDesc = true
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if isDesc && content != "" {
				description = content
			}
		}
	}

	// Recursively traverse children
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		t, d := extractMeta(c)
		if t != "" {
			title = t
		}
		if d != "" {
			description = d
		}
	}

	return title, description
}

func main() {
	e := echo.New()

	// Register the handler
	e.POST("/preview", FetchURLPreview)

	// Start server
	if err := e.Start(":8080"); err != nil {
		log.Fatal(err)
	}
}

