package main

import (
	"io"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// RequestPayload defines the JSON request structure
type RequestPayload struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse a URL
func FetchURLPreview(c echo.Context) error {
	var req RequestPayload
	// Bind the JSON body to the struct
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON format"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Check for non-200 status codes
	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Server returned non-200 status"})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML traverses the HTML node tree to find the title and meta description
func parseHTML(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)

	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
						break
					}
				}
				if isDesc {
					for _, attr := range n.Attr {
						if attr.Key == "content" {
							description = attr.Val
							break
						}
					}
				}
			}
		}
		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	if err := e.Start(":8080"); err != nil {
		log.Fatal(err)
	}
}

