type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL content
func FetchURLPreview(c echo.Context) error {
	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusGatewayTimeout, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Unexpected status code: %d", resp.StatusCode)})
	}

	// Parse the HTML content to extract title and description
	title, description := parseHTML(resp.Body)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML traverses the HTML node tree to find the title and meta description
func parseHTML(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract meta description
			if n.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
