type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload defines the JSON response structure
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL content
func FetchURLPreview(c echo.Context) error {
	var req RequestPayload
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Unexpected status code: %d", resp.StatusCode)})
	}

	// Parse the HTML to extract title and description
	title, description, err := extractHTMLInfo(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// Return the result as JSON
	return c.JSON(http.StatusOK, ResponsePayload{
		Title:       title,
		Description: description,
	})
}

// extractHTMLInfo traverses the HTML DOM to find the title and meta description
func extractHTMLInfo(r io.Reader) (string, string, error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var title, description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var isDescription bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDescription = true
						break
					}
				}
				if isDescription {
					for _, attr := range n.Attr {
						if attr.Key == "content" {
							description = attr.Val
							break
						}
					}
				}
			}
		}

		// Recursively traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description, nil
}

func main() {
