	var req URLRequest
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL field is required"})
	}

	// Create a new HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Perform the GET request
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check for non-200 status codes
