type RequestPayload struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON structure for the response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse URL content
func FetchURLPreview(c echo.Context) error {
	var payload RequestPayload
	if err := c.Bind(&payload); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	if payload.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create a client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(payload.URL)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Unexpected status code: %d", resp.StatusCode)})
	}

	// Parse HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	title, description := extractMetaInfo(doc)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetaInfo traverses the HTML node tree to find title and meta description
func extractMetaInfo(n *html.Node) (string, string) {
	var title, description string

	var traverse func(*html.Node)
	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && node.FirstChild != nil {
				title = node.FirstChild.Data
			}
			// Extract Meta Description
			if node.Data == "meta" {
				var name, content string
				for _, attr := range node.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" && description == "" {
					description = content
				}
			}
		}

		// Recursively traverse children
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			traverse(child)
		}
	}

	traverse(n)
	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
