)

// URLRequest defines the expected JSON payload
type URLRequest struct {
	URL string `json:"url"`
}

// URLPreview defines the JSON response
type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to generate a URL preview
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Create an HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusServiceUnavailable, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "received non-200 status code"})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body)

	// Return the result as JSON
	return ctx.JSON(http.StatusOK, URLPreview{
		Title:       title,
		Description: description,
	})
}

// parseHTML traverses the HTML node tree to find the title and meta description
func parseHTML(r io.Reader) (string, string) {
	var title, description string

	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		// Stop traversing if we found both to save resources
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}

			// Extract Meta Description
			if n.Data == "meta" && description == "" {
				var isDesc bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	log.Println("Server started on :8080")
	if err := e.Start(":8080"); err != nil {
		log.Fatal("Failed to start server:", err)
	}
}

