// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(c echo.Context) error {
	var req Request
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Create HTTP client with 3-second timeout as requested
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("unexpected status code: %d", resp.StatusCode)})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body)

	return c.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// parseHTML traverses the HTML node tree to find the title and meta description
func parseHTML(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)

	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract Meta Description
			if n.Data == "meta" {
				isDescription := false
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
