import (
	"context"
	"fmt"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// RequestPayload defines the JSON request structure
type RequestPayload struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx echo.Context) error {
	var payload RequestPayload
	if err := ctx.Bind(&payload); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "Invalid request body"})
	}

	if payload.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL field is required"})
	}

	// Create a context with a 3-second timeout as required
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	// Create a new HTTP request
	req, err := http.NewRequestWithContext(reqCtx, "GET", payload.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to create request"})
	}

	// Set a User-Agent to avoid being blocked by some servers
	req.Header.Set("User-Agent", "Go-URL-Preview/1.0")

	// Execute the request
	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		if err == context.DeadlineExceeded {
			return ctx.JSON(http.StatusRequestTimeout, PreviewResponse{Error: "Request timed out"})
		}
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", resp.StatusCode)})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "Failed to parse HTML"})
	}

	var title, description string

	// Traverse the HTML node tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract Meta Description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	if err := e.Start(":8080"); err != nil {
		log.Fatal(err)
	}
}

