)

// RequestPayload defines the expected JSON input
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload defines the JSON output
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch and parse a URL
func FetchURLPreview(c echo.Context) error {
	var req RequestPayload
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	// Create a client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("unexpected status code: %d", resp.StatusCode)})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	// Extract metadata
	title, description := extractMeta(doc)

	return c.JSON(http.StatusOK, ResponsePayload{
		Title:       title,
		Description: description,
	})
}

// extractMeta traverses the HTML node tree to find title and meta description
func extractMeta(n *html.Node) (string, string) {
	var title, description string

	var f func(*html.Node)
	f = func(node *html.Node) {
		if node.Type == html.ElementNode {
			// Extract Title
			if node.Data == "title" && node.FirstChild != nil {
				title = node.FirstChild.Data
			}

			// Extract Meta Description
			if node.Data == "meta" {
				var isDesc bool
				var content string
				for _, attr := range node.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDesc {
					description = content
				}
			}
		}
		// Recursively traverse children
		for c := node.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return title, description
}

func main() {
	e := echo.New()

	// Register the handler under the /preview path
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Logger.Fatal(e.Start(":8080"))
}

