	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	html := string(htmlContent)
	lowerHtml := strings.ToLower(html)

	// Extract Title
	title := ""
	titleStartTag := strings.Index(lowerHtml, "<title")
	if titleStartTag != -1 {
		titleStart := strings.Index(lowerHtml[titleStartTag:], ">")
		if titleStart != -1 {
			titleStart += titleStartTag + 1
			titleEnd := strings.Index(lowerHtml[titleStart:], "</title>")
			if titleEnd != -1 {
				title = strings.TrimSpace(html[titleStart : titleStart+titleEnd])
			}
		}
	}

	// Extract Description
	description := ""
	currentPos := 0
	for {
		metaStart := strings.Index(lowerHtml[currentPos:], "<meta")
		if metaStart == -1 {
			break
		}
		metaStart += currentPos

		metaEnd := strings.Index(lowerHtml[metaStart:], ">")
		if metaEnd == -1 {
			break
		}
		metaEnd += metaStart

		tagContent := lowerHtml[metaStart:metaEnd]

		// Check for name="description" (case-insensitive via lowerHtml)
		if strings.Contains(tagContent, `name="description"`) || strings.Contains(tagContent, `name='description'`) {
			// Extract content
			// Try double quotes
			if idx := strings.Index(tagContent, `content="`); idx != -1 {
				contentStart := idx + len(`content="`)
				contentEnd := strings.Index(tagContent[contentStart:], `"`)
				if contentEnd != -1 {
					description = strings.TrimSpace(html[metaStart+contentStart : metaStart+contentStart+contentEnd])
					break
				}
			} else if idx := strings.Index(tagContent, `content='`); idx != -1 { // Try single quotes
				contentStart := idx + len(`content='`)
				contentEnd := strings.Index(tagContent[contentStart:], `'`)
				if contentEnd != -1 {
					description = strings.TrimSpace(html[metaStart+contentStart : metaStart+contentStart+contentEnd])
					break
				}
			}
		}

		currentPos = metaEnd
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

