// RequestPayload defines the structure of the incoming JSON request
type RequestPayload struct {
	URL string `json:"url"`
}

// PreviewResponse defines the structure of the JSON response
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST /preview request
func FetchURLPreview(c echo.Context) error {
	var req RequestPayload
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON format"})
	}

	if req.URL == "" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with a 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the content from the URL
	resp, err := client.Get(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusBadGateway, map[string]string{"error": "Server returned non-200 status"})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
